#include <iostream>
#include <vector>
#include <unordered_set>

using namespace std;

bool containsDuplicate(vector<int> &numbers)
{
    unordered_set<int> seen;

    for (int n : numbers)
    {
        if (seen.count(n))
        {
            return true; // already seen this exact value
        }
        seen.insert(n);
    }
    return false;
}

int main()
{
    vector<int> a = {1, 2, 3, 1};
    vector<int> b = {1, 2, 3, 4};

    cout << containsDuplicate(a) << endl;
    cout << containsDuplicate(b) << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <unordered_set>

using namespace std;

int longestConsecutive(vector<int> &numbers)
{
    unordered_set<int> numSet(numbers.begin(), numbers.end());
    int longest = 0;

    for (int n : numSet)
    {
        if (!numSet.count(n - 1)) // only start counting if n is the START of a sequence
        {
            int length = 1;
            int current = n;

            while (numSet.count(current + 1))
            {
                current++;
                length++;
            }

            longest = max(longest, length);
        }
    }
    return longest;
}

int main()
{
    vector<int> numbers = {100, 4, 200, 1, 3, 2};

    cout << longestConsecutive(numbers) << endl;

    return 0;
}

